const body = $input.first().json.body;
const events = body.events || [];
if (!events.length) return [{ json: { skip: true } }];

const event = events[0];
const userId     = event.source?.userId || 'unknown';
const msgType    = event.message?.type  || 'unknown';
const replyToken = event.replyToken || '';

let content = '';
let imageId  = null;

if (msgType === 'text') {
  content = event.message.text;
} else if (msgType === 'image') {
  content = '[IMAGE]';
  imageId = event.message.id;
} else if (msgType === 'location') {
  content = '[LOCATION] lat:' + event.message.latitude + ' lng:' + event.message.longitude + ' addr:' + event.message.address;
}

return [{
  json: {
    userId,
    messageId: event.message?.id || '',
    messageType: msgType,
    content,
    imageId,
    replyToken,
    timestamp: new Date(event.timestamp).toISOString()
  }
}];

const today = new Date().toISOString().split('T')[0];

const orders   = $('Fetch Orders').all().map(r => r.json);
const payments = $('Fetch Payments').all().map(r => r.json);

const todayOrders   = orders.filter(r   => (r.timestamp || '').startsWith(today));
const todayPayments = payments.filter(r => (r.timestamp || '').startsWith(today));

const totalRevenue = todayPayments
  .filter(r => r.is_duplicate !== 'true' && r.is_duplicate !== true)
  .reduce((sum, r) => sum + (parseFloat(r.payment_amount) || 0), 0);

const orderCount     = todayOrders.length;
const paidCount      = todayPayments.length;
const duplicateCount = todayPayments.filter(r => r.is_duplicate === 'true' || r.is_duplicate === true).length;
const pendingList    = todayOrders.filter(r => (r.auto_tags || '').includes('Pending_Payment'));
const highPriority   = todayOrders.filter(r => (r.auto_tags || '').includes('High_Priority')).length;

const productCount = {};
todayOrders.forEach(r => {
  if (r.product_name) productCount[r.product_name] = (productCount[r.product_name] || 0) + 1;
});
const topProducts = Object.entries(productCount)
  .sort((a, b) => b[1] - a[1]).slice(0, 3)
  .map(([name, count]) => '• ' + name + ' (' + count + ' ออเดอร์)').join('\n') || 'ไม่มีข้อมูล';

const pendingNames = pendingList
  .map(r => '• ' + (r.recipient_name || r.userId)).join('\n') || 'ไม่มี';

const message = '📊 ChatBuddy รายงานประจำวัน\n'
  + '📅 ' + today + '\n'
  + '━━━━━━━━━━━━━━━\n'
  + '💰 ยอดขายรวม: ' + totalRevenue.toLocaleString() + ' บาท\n'
  + '📦 ออเดอร์: ' + orderCount + ' รายการ\n'
  + '✅ ชำระแล้ว: ' + paidCount + ' รายการ\n'
  + '⚠️ สลิปซ้ำ: ' + duplicateCount + ' รายการ\n'
  + '⏳ รอชำระ: ' + pendingList.length + ' รายการ\n'
  + '🚨 High Priority: ' + highPriority + ' เคส\n'
  + '━━━━━━━━━━━━━━━\n'
  + '🏆 สินค้าขายดีวันนี้:\n' + topProducts + '\n'
  + '━━━━━━━━━━━━━━━\n'
  + '⚠️ ลูกค้ารอชำระ:\n' + pendingNames;

return [{ json: { message } }];

// ดึง Output จาก AI Agent
const agentOutput = $input.first().json.output || $input.first().json.text || '';
// ดึง Data เดิมจาก Webhook/Payload ก่อนหน้า
const prev = $('Pre-process Payload').first().json;

let parsed;
try {
  // ทำความสะอาด String ที่อาจมี Markdown JSON ติดมา
  const cleaned = agentOutput.replace(/```json/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  // กรณี Parse JSON ไม่สำเร็จ ให้ตั้งค่า Default
  parsed = {
    intent: 'Other',
    sentiment: 'Neutral',
    status: 'Completed', // Default status
    summary: 'วิเคราะห์ไม่ได้',
    reply_message: 'ขอโทษค่ะ ระบบขัดข้องชั่วคราว กรุณาลองใหม่อีกครั้งนะคะ 🙏',
    entities: { total_cost: '' }
  };
}

// ส่งค่ากลับออกไปเพื่อใช้ใน Node ต่อๆ ไป
return [{
  json: {
    ...prev,
    intent:        parsed.intent        || 'Other',
    sentiment:     parsed.sentiment     || 'Neutral',
    status:        parsed.status        || 'Completed', // เพิ่มฟิลด์ status ตรงนี้
    summary:       parsed.summary       || '',
    reply_message: parsed.reply_message || '',
    entities:      Object.assign({}, parsed.entities || {}, { total_cost: (parsed.entities && parsed.entities.total_cost) || '' }),
    // ลบ auto_tags ออกตามที่ต้องการ
    analyzedAt:    new Date().toISOString()
  }
}];

const prev = $('Pre-process Payload').first().json;
return [{
  json: {
    ...prev,
    intent: 'Payment_Proof',
    sentiment: 'Neutral',
    summary: 'สลิปไม่ตรงกับเงื่อนไขที่ตั้งไว้',
    entities: {},
    auto_tags: '#Slip_Not_Matched',
    slipValid: false,
    isDuplicate: false
  }
}];

const agentData = $('Parse Agent Response').first().json;
const prevData = $('Pre-process Payload').first().json;

const currentEntity = agentData.entities || {};

// ยกเลิกการทวงข้อมูลจาก node นี้ เพราะจะให้ AI เป็นคนทวงและตอบกลับเอง
let isComplete = false;
const rName = currentEntity.recipient_name && currentEntity.recipient_name !== '-' ? currentEntity.recipient_name : "";
const pNum = currentEntity.phone_number && currentEntity.phone_number !== '-' ? currentEntity.phone_number : "";
const sAddr = currentEntity.shipping_address && currentEntity.shipping_address !== '-' ? currentEntity.shipping_address : "";

if (rName && pNum && sAddr) {
    isComplete = true;
}

return [{
    json: {
        replyToken: prevData.replyToken,
        reply_message: agentData.reply_message || '', // ปล่อยผ่านข้อความของ AI ไปเลยเต็มๆ
        is_complete: isComplete,
        // ข้อมูลสำหรับลง Google Sheet
        status: isComplete ? "Completed" : "Incomplete",
        sentiment: agentData.sentiment,
        recipient_name: rName || '-',
        shipping_address: sAddr || '-',
        phone_number: pNum || '-',
        auto_tags: Array.isArray(agentData.auto_tags) ? agentData.auto_tags.join(',') : agentData.auto_tags
    }
}];

